#### 2. 核心代码原型 (`server.py`)
这是一个可以复制粘贴到任何 FastAPI/Flask 项目中的片段。

```python
import socket
import json
import threading
import logging

logger = logging.getLogger("ai-discover")

class DiscoveryServer:
    def __init__(self, service_name: str, http_port: int, manifest_path: str = "/ai_manifest", udp_port: int = 53535):
        self.service_name = service_name
        self.http_port = http_port
        self.manifest_path = manifest_path
        self.udp_port = udp_port
        self._running = False
        self._thread = None

    def start(self):
        """在非守护线程中启动 UDP 监听"""
        if self._running:
            return
        self._running = True
        self._thread = threading.Thread(target=self._listen_loop, daemon=False) # daemon=False 防止主进程退出时瞬间被杀，视需求而定
        self._thread.start()
        logger.info(f"AI Discovery Server started on UDP {self.udp_port}")

    def stop(self):
        self._running = False
        if self._thread:
            self._thread.join()

    def _listen_loop(self):
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        # 绑定到所有接口
        sock.bind(('0.0.0.0', self.udp_port))
        sock.settimeout(1.0) # 用于定期检查 _running 标志

        while self._running:
            try:
                data, addr = sock.recvfrom(1024)
                message = data.decode('utf-8').strip()

                if message.startswith("AI_DISCOVER_REQ"):
                    # 解析请求获取 query_id (简单处理，取第二行)
                    try:
                        payload = json.loads(message.split('\n', 1)[1])
                        query_id = payload.get('query_id', 'unknown')

                        response_payload = {
                            "query_id": query_id,
                            "status": "ok",
                            "service_name": self.service_name,
                            "http_port": self.http_port,
                            "manifest_path": self.manifest_path,
                            "version": "1.0"
                        }

                        response_str = f"AI_DISCOVER_RES\n{json.dumps(response_payload)}"
                        sock.sendto(response_str.encode('utf-8'), addr)
                        logger.debug(f"Responded to discovery from {addr}")
                    except Exception as e:
                        logger.warning(f"Invalid discovery request: {e}")

            except socket.timeout:
                continue
            except OSError:
                break
        sock.close()

