#     server = DiscoveryServer(service_name="MyPDFTool", http_port=8000)
#     server.start()
#     # ... 启动你的 FastAPI app ...
```

#### 3. 客户端扫描原型 (`client.py`)

```python
import socket
import json
import requests
from typing import List, Dict, Any

class DiscoveryClient:
    def __init__(self, udp_port: int = 53535, timeout: float = 2.0):
        self.udp_port = udp_port
        self.timeout = timeout

    def scan(self) -> List[Dict[str, Any]]:
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1)
        sock.settimeout(self.timeout)

        req_msg = "AI_DISCOVER_REQ\n{\"query_id\": \"scan-001\", \"version\": \"1.0\"}"

        # 发送广播
        sock.sendto(req_msg.encode('utf-8'), ('<broadcast>', self.udp_port))

        services = []
        seen_ips = set()

        print("Scanning network...")
        try:
            while True:
                data, addr = sock.recvfrom(4096)
                ip = addr[0]

                if ip in seen_ips:
                    continue

                message = data.decode('utf-8').strip()
                if message.startswith("AI_DISCOVER_RES"):
                    try:
                        payload = json.loads(message.split('\n', 1)[1])
                        if payload.get('status') == 'ok':
                            # 构建 Manifest URL
                            manifest_url = f"http://{ip}:{payload['http_port']}{payload['manifest_path']}"

                            # 尝试获取详细 Manifest (可选：这里可以加异步并发优化)
                            try:
                                resp = requests.get(manifest_url, timeout=2)
                                if resp.status_code == 200:
                                    full_info = resp.json()
                                    full_info['_discovery_ip'] = ip
                                    full_info['_discovery_port'] = payload['http_port']
                                    services.append(full_info)
                                    seen_ips.add(ip)
                                    print(f"✅ Found: {full_info.get('meta', {}).get('name', 'Unknown')} at {ip}")
                            except requests.exceptions.RequestException:
                                print(f"⚠️ Found service at {ip} but failed to fetch manifest")

                    except json.JSONDecodeError:
                        continue
        except socket.timeout:
            pass
        finally:
            sock.close()

        return services
```

