#### 2. 核心代码原型 (`lib.rs`)

```rust
use tokio::net::UdpSocket;
use serde::{Deserialize, Serialize};
use std::net::SocketAddr;
use std::sync::Arc;

const UDP_PORT: u16 = 53535;
const REQ_HEADER: &str = "AI_DISCOVER_REQ";
const RES_HEADER: &str = "AI_DISCOVER_RES";

#[derive(Serialize, Deserialize, Debug)]
struct DiscoverReq {
    query_id: String,
    version: String,
}

#[derive(Serialize, Deserialize, Debug)]
struct DiscoverRes {
    query_id: String,
    status: String,
    service_name: String,
    http_port: u16,
    manifest_path: String,
}

/// 服务端结构体
pub struct DiscoveryServer {
    service_name: String,
    http_port: u16,
    manifest_path: String,
}

impl DiscoveryServer {
    pub fn new(service_name: &str, http_port: u16, manifest_path: &str) -> Self {
        Self {
            service_name: service_name.to_string(),
            http_port,
            manifest_path: manifest_path.to_string(),
        }
    }

    pub async fn run(&self) -> anyhow::Result<()> {
        let addr = format!("0.0.0.0:{}", UDP_PORT);
        let socket = UdpSocket::bind(&addr).await?;
        log::info!("AI Discovery Server listening on {}", addr);

        let mut buf = [0; 1024];
        let service_name = self.service_name.clone();
        let http_port = self.http_port;
        let manifest_path = self.manifest_path.clone();

        loop {
            let (len, src) = socket.recv_from(&mut buf).await?;
            let msg = String::from_utf8_lossy(&buf[..len]);

            if msg.starts_with(REQ_HEADER) {
                // 简单解析换行后的 JSON
                if let Some(json_part) = msg.splitn(2, '\n').nth(1) {
                    if let Ok(req) = serde_json::from_str::<DiscoverReq>(json_part) {
                        let res = DiscoverRes {
                            query_id: req.query_id,
                            status: "ok".to_string(),
                            service_name: service_name.clone(),
                            http_port,
                            manifest_path: manifest_path.clone(),
                        };

                        let res_str = format!("{}\n{}", RES_HEADER, serde_json::to_string(&res)?);
                        socket.send_to(res_str.as_bytes(), src).await?;
                        log::debug!("Responded to {}", src);
                    }
                }
            }
        }
    }
}

