```python
import socket
import json
import threading
import logging
from typing import Optional

logger = logging.getLogger("ai-discover")

class DiscoveryServer:
    def __init__(
        self, 
        service_name: str, 
        http_port: int, 
        manifest_path: str = "/ai_manifest",
        udp_port: int = 53535,
        service_id: Optional[str] = None
    ):
        self.service_name = service_name
        self.http_port = http_port
        self.manifest_path = manifest_path
        self.udp_port = udp_port
        self.service_id = service_id or service_name.lower().replace(" ", "-")
        self._running = False
        self._socket: Optional[socket.socket] = None
        self._thread: Optional[threading.Thread] = None

    def start(self):
        """启动 UDP 监听线程"""
        if self._running:
            logger.warning("Discovery server already running.")
            return

        self._running = True
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)

        try:
            self._socket.bind(('0.0.0.0', self.udp_port))
            self._socket.settimeout(1.0)

            self._thread = threading.Thread(target=self._listen_loop, daemon=True)
            self._thread.start()
            logger.info(f"AI Discovery Server started on UDP port {self.udp_port}")
        except OSError as e:
            logger.error(f"Failed to bind UDP port {self.udp_port}: {e}")
            self._running = False

    def stop(self):
        """停止监听"""
        self._running = False
        if self._socket:
            self._socket.close()
        if self._thread:
            self._thread.join(timeout=2.0)
        logger.info("AI Discovery Server stopped.")

    def _listen_loop(self):
        while self._running:
            try:
                data, addr = self._socket.recvfrom(1024)
                message = data.decode('utf-8').strip()

                if message.startswith("AI_DISCOVER_REQ"):
                    self._handle_request(message, addr)
            except socket.timeout:
                continue
            except OSError:
                break
            except Exception as e:
                logger.error(f"Error in discovery loop: {e}")

    def _handle_request(self, message: str, addr: tuple):
        try:
            lines = message.split('\n', 1)
            if len(lines) < 2:
                return

            payload = json.loads(lines[1])
            query_id = payload.get('query_id', 'unknown')

            response_data = {
                "query_id": query_id,
                "status": "ok",
                "service_name": self.service_name,
                "service_id": self.service_id,
                "http_port": self.http_port,
                "manifest_path": self.manifest_path,
                "version": "1.0"
            }

            response_str = f"AI_DISCOVER_RES\n{json.dumps(response_data)}"
            self._socket.sendto(response_str.encode('utf-8'), addr)
            logger.debug(f"Responded to discovery from {addr}")

        except json.JSONDecodeError:
            logger.warning("Invalid JSON in discovery request")
        except Exception as e:
            logger.error(f"Error handling request: {e}")

