```python
import socket
import json
import requests
from typing import List, Dict, Any, Optional
import logging

logger = logging.getLogger("ai-discover")

class DiscoveredService:
    def __init__(self, info: Dict[str, Any], manifest: Optional[Dict[str, Any]] = None):
        self.info = info
        self.manifest = manifest
        self.ip = info.get('_ip')
        self.port = info.get('http_port')
        self.name = info.get('service_name')
        self.url = f"http://{self.ip}:{self.port}{info.get('manifest_path', '/ai_manifest')}"

    def __repr__(self):
        return f"<Service {self.name} at {self.ip}:{self.port}>"

class DiscoveryClient:
    def __init__(self, udp_port: int = 53535, timeout: float = 2.0, fetch_manifest: bool = True):
        self.udp_port = udp_port
        self.timeout = timeout
        self.fetch_manifest = fetch_manifest

    def scan(self) -> List[DiscoveredService]:
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1)
        sock.settimeout(self.timeout)

        req_msg = "AI_DISCOVER_REQ\n{\"query_id\": \"scan-req-001\", \"version\": \"1.0\"}"
        services = []
        seen_ids = set()

        logger.info("Starting AI service discovery broadcast...")
        try:
            sock.sendto(req_msg.encode('utf-8'), ('<broadcast>', self.udp_port))

            while True:
                try:
                    data, addr = sock.recvfrom(4096)
                    ip = addr[0]
                    message = data.decode('utf-8').strip()

                    if not message.startswith("AI_DISCOVER_RES"):
                        continue

                    lines = message.split('\n', 1)
                    if len(lines) < 2:
                        continue

                    payload = json.loads(lines[1])
                    service_id = payload.get('service_id', payload.get('service_name'))

                    if service_id in seen_ids:
                        continue

                    if payload.get('status') == 'ok':
                        seen_ids.add(service_id)
                        payload['_ip'] = ip

                        manifest_data = None
                        if self.fetch_manifest:
                            manifest_url = f"http://{ip}:{payload['http_port']}{payload['manifest_path']}"
                            try:
                                resp = requests.get(manifest_url, timeout=2)
                                if resp.status_code == 200:
                                    manifest_data = resp.json()
                            except Exception as e:
                                logger.warning(f"Failed to fetch manifest from {ip}: {e}")

                        services.append(DiscoveredService(payload, manifest_data))
                        logger.info(f"Found: {payload['service_name']} at {ip}:{payload['http_port']}")

                except socket.timeout:
                    break
        finally:
            sock.close()

        return services
```

