#### 4.2.2 核心代码 (`lib.rs`)
```rust
use tokio::net::UdpSocket;
use serde::{Deserialize, Serialize};
use std::net::SocketAddr;
use std::sync::Arc;
use log::{info, debug, warn, error};

const DEFAULT_UDP_PORT: u16 = 53535;
const REQ_HEADER: &str = "AI_DISCOVER_REQ";
const RES_HEADER: &str = "AI_DISCOVER_RES";

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct DiscoverReq {
    pub query_id: String,
    pub version: String,
}

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct DiscoverRes {
    pub query_id: String,
    pub status: String,
    pub service_name: String,
    pub service_id: String,
    pub http_port: u16,
    pub manifest_path: String,
    pub version: String,
}

pub struct DiscoveryServer {
    service_name: String,
    service_id: String,
    http_port: u16,
    manifest_path: String,
    udp_port: u16,
}

impl DiscoveryServer {
    pub fn new(service_name: &str, http_port: u16, manifest_path: &str) -> Self {
        let service_id = service_name.to_lowercase().replace(" ", "-");
        Self {
            service_name: service_name.to_string(),
            service_id,
            http_port,
            manifest_path: manifest_path.to_string(),
            udp_port: DEFAULT_UDP_PORT,
        }
    }

    pub fn with_port(mut self, udp_port: u16) -> Self {
        self.udp_port = udp_port;
        self
    }

    pub async fn run(&self) -> anyhow::Result<()> {
        let addr = format!("0.0.0.0:{}", self.udp_port);
        let socket = UdpSocket::bind(&addr).await?;
        info!("AI Discovery Server listening on {}", addr);

        let service_name = self.service_name.clone();
        let service_id = self.service_id.clone();
        let http_port = self.http_port;
        let manifest_path = self.manifest_path.clone();
        let version = "1.0".to_string();

        let mut buf = [0u8; 1024];
        loop {
            match socket.recv_from(&mut buf).await {
                Ok((len, src)) => {
                    let msg = String::from_utf8_lossy(&buf[..len]);
                    if msg.starts_with(REQ_HEADER) {
                        if let Some(json_part) = msg.splitn(2, '\n').nth(1) {
                            match serde_json::from_str::<DiscoverReq>(json_part) {
                                Ok(req) => {
                                    let res = DiscoverRes {
                                        query_id: req.query_id,
                                        status: "ok".to_string(),
                                        service_name: service_name.clone(),
                                        service_id: service_id.clone(),
                                        http_port,
                                        manifest_path: manifest_path.clone(),
                                        version: version.clone(),
                                    };

                                    let res_str = format!("{}\n{}", RES_HEADER, serde_json::to_string(&res)?);
                                    if let Err(e) = socket.send_to(res_str.as_bytes(), src).await {
                                        error!("Failed to send response: {}", e);
                                    } else {
                                        debug!("Responded to {}", src);
                                    }
                                }
                                Err(e) => warn!("Invalid JSON in request: {}", e),
                            }
                        }
                    }
                }
                Err(e) => error!("Receive error: {}", e),
            }
        }
    }
}

